# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal) extends BankMessage
case class Withdraw(amount: BigDecimal) extends BankMessage
case object GetBalance extends BankMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionResult(success: Boolean, message: String, currentBalance: BigDecimal)

// Account Actor - processes messages sequentially via actor mailbox
// Note: Using `var` here is safe because Akka actors process one message at a time,
// providing built-in concurrency safety through the actor model.
// No external synchronization is needed because the actor's mailbox serializes access.
class AccountActor(accountId: String) extends Actor {

  // This var is safe within an actor context because Akka guarantees
  // single-threaded message processing per actor instance.
  // The actor mailbox acts as the synchronization mechanism.
  private var balance: BigDecimal = BigDecimal(0)

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= 0) {
        sender() ! TransactionResult(
          success = false,
          message = s"Invalid deposit amount: $amount. Must be positive.",
          currentBalance = balance
        )
      } else {
        balance += amount
        sender() ! TransactionResult(
          success = true,
          message = s"Deposited $amount to account $accountId",
          currentBalance = balance
        )
      }

    case Withdraw(amount) =>
      if (amount <= 0) {
        sender() ! TransactionResult(
          success = false,
          message = s"Invalid withdrawal amount: $amount. Must be positive.",
          currentBalance = balance
        )
      } else if (amount > balance) {
        sender() ! TransactionResult(
          success = false,
          message = s"Insufficient funds in account $accountId. Available: $balance, Requested: $amount",
          currentBalance = balance
        )
      } else {
        balance -= amount
        sender() ! TransactionResult(
          success = true,
          message = s"Withdrew $amount from account $accountId",
          currentBalance = balance
        )
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

object AccountActor {
  def props(accountId: String): Props = Props(new AccountActor(accountId))
}

// Bank manager that routes to per-account actors for scalability
class BankManagerActor extends Actor {
  import scala.collection.mutable

  private val accounts: mutable.Map[String, akka.actor.ActorRef] = mutable.Map.empty

  private def getOrCreateAccount(accountId: String): akka.actor.ActorRef = {
    accounts.getOrElseUpdate(accountId, {
      context.actorOf(AccountActor.props(accountId), s"account-$accountId")
    })
  }

  override def receive: Receive = {
    case (accountId: String, msg: BankMessage) =>
      val accountActor = getOrCreateAccount(accountId)
      accountActor.forward(msg)
  }
}

object BankManagerActor {
  def props: Props = Props(new BankManagerActor)
}

// Demo application
object BankingApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("BankingSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  import system.dispatcher

  val bankManager = system.actorOf(BankManagerActor.props, "bank-manager")

  // Simulate concurrent transactions
  val futures: Seq[Future[Any]] = Seq(
    bankManager ? ("acc-001", Deposit(BigDecimal(1000))),
    bankManager ? ("acc-001", Deposit(BigDecimal(500))),
    bankManager ? ("acc-002", Deposit(BigDecimal(2000))),
    bankManager ? ("acc-001", Withdraw(BigDecimal(200))),
    bankManager ? ("acc-002", Withdraw(BigDecimal(3000))), // Should fail - insufficient funds
    bankManager ? ("acc-001", GetBalance),
    bankManager ? ("acc-002", GetBalance)
  )

  // Process results sequentially for display
  futures.foreach { future =>
    val result = Await.result(future, 5.seconds)
    result match {
      case TransactionResult(success, message, currentBalance) =>
        println(s"[${if (success) "OK" else "FAIL"}] $message (Balance: $currentBalance)")
      case BalanceResponse(bal) =>
        println(s"[QUERY] Current balance: $bal")
    }
  }

  // High-throughput stress test
  println("\n--- High-throughput stress test ---")
  val stressAccount = "stress-test-001"
  val numTransactions = 10000

  val depositFutures = (1 to numTransactions).map { _ =>
    bankManager ? (stressAccount, Deposit(BigDecimal(1)))
  }

  val allDeposits = Future.sequence(depositFutures)
  Await.result(allDeposits, 30.seconds)

  val finalBalance = Await.result(bankManager ? (stressAccount, GetBalance), 5.seconds)
  finalBalance match {
    case BalanceResponse(bal) =>
      println(s"After $numTransactions deposits of 1 each, balance = $bal (expected: $numTransactions)")
      assert(bal == BigDecimal(numTransactions), s"Balance mismatch! Got $bal, expected $numTransactions")
      println("Consistency check PASSED ✓")
  }

  system.terminate()
}